    print "This appears to be a ZIP file at offset $pk\n";

    # Parse ZIP local file headers
    my $pos = $pk;
    my $count = 0;
    while ($pos < length($data) - 30 && $count < 10) {
        my $sig = substr($data, $pos, 4);
        if ($sig eq "PK\x03\x04") {
            # Read filename length and extra field length
            my $fnlen = unpack("v", substr($data, $pos+26, 2));
            my $exlen = unpack("v", substr($data, $pos+28, 2));
            my $comlen = unpack("v", substr($data, $pos+30, 2));
            my $uncomp_size = unpack("V", substr($data, $pos+18, 4));
            my $comp_size = unpack("V", substr($data, $pos+20, 4));
            my $fname = substr($data, $pos+46, $fnlen);

            print "File #$count: name=$fname, uncomp=$uncomp_size, comp=$comp_size\n";

            # Try to extract and look for PASSWORD
            if ($fname =~ /launchcode/i) {
                my $file_data_start = $pos + 46 + $fnlen + $exlen + $comlen;
                my $file_data = substr($data, $file_data_start, $comp_size);

                # Try decompressing
                use Compress::Zlib;
                my $d = new Compress::Zlib();
                my $result = $d->inflate($file_data);
                if ($result && $result =~ /PASSWORD=/) {
                    print "Found PASSWORD in ZIP entry: $1\n" if $result =~ /(PASSWORD=[A-Z0-9]+)/;
                } else {
                    # Try raw
                    if ($file_data =~ /(PASSWORD=[A-Z0-9]+)/) {
                        print "Found raw PASSWORD in ZIP entry: $1\n";
                    }
                }
            }

            $pos = $file_data_start + $comp_size;
            $count++;
        } else {
            last;
        }
    }
