my $difat_sectors = unpack("V", substr($data, 44, 4));
print "DIFAT sectors: $difat_sectors\n";

# Read DIFAT table (starts at offset 76, 109 entries of 4 bytes each)
print "\nDIFAT entries:\n";
for my $i (0..109) {
    my $off = 76 + $i * 4;
    my $val = unpack("V", substr($data, $off, 4));
    if ($val != 0xFFFFFFFF && $val < 1000000) {
        print "  [$i] = $val\n";
    }
}

# Read FAT sectors
my @fat_sectors;
my $sector_size_bytes = $sector_size;
my $fat_start_sector = unpack("V", substr($data, 48, 4)); # First FAT sector
print "\nFirst FAT sector: $fat_start_sector\n";

# Actually, let me read the FAT from the FAT chain
my @all_fat_sectors;
my $sector = unpack("V", substr($data, 48, 4)); # First FAT sector
while ($sector >= 0 && $sector < 1000000 && scalar(@all_fat_sectors) < 100) {
    push @all_fat_sectors, $sector;
    my $next = unpack("V", substr($data, $sector * $sector_size_bytes + ($sector_size_bytes - 4), 4));
    $sector = $next;
}
print "FAT sectors: " . scalar(@all_fat_sectors) . "\n";

# Read directory entries
my $dir_sector_num = unpack("V", substr($data, 48, 4));
my $dir_offset = $dir_sector_num * $sector_size_bytes;
print "\nDirectory sector offset: $dir_offset\n";

# Parse directory entries (each is 128 bytes)
for my $i (0..63) {
    my $entry_off = $dir_offset + $i * 128;
    if ($entry_off + 128 > length($data)) { last; }

    # Read name length (bytes 64-65)
    my $name_len = unpack("v", substr($data, $entry_off + 64, 2));
    next if $name_len == 0;

    # Read name (UTF-16LE)
    my $name = "";
    for my $j (0..$name_len/2-1) {
        my $off = $entry_off + $j * 2;
        my $lo = ord(substr($data, $off, 1));
        my $hi = ord(substr($data, $off+1, 1));
        my $char = chr($lo + ($hi << 8));
        $name .= $char;
    }

    # Read entry type (byte 66)
    my $type = ord(substr($data, $entry_off + 66));
    my $type_str = ($type == 1) ? "stream" : ($type == 2) ? "directory" : ($type == 5) ? "root" : "unknown($type)";

    # Read starting sector (bytes 116-119)
    my $start_sector = unpack("V", substr($data, $entry_off + 116, 4));

    # Read size (bytes 116-119 for regular entries, but actually bytes 116-119 is start sector, 120-123 is size)
    my $size = unpack("V", substr($data, $entry_off + 120, 4));

    printf "Entry %d: name=[%s] type=%s start_sector=%d size=%d\n", $i, $name, $type_str, $start_sector, $size;
}
'
